<div class="d-flex justify-content-between align-items-center mb-4"><h1 class="h3">Recurring Services</h1><form method="post" action="/portal/recurring/generate"><?=csrf_field()?><button class="btn btn-warning"><i class="fa-solid fa-arrows-rotate me-2"></i>Generate Due Jobs</button></form></div><div class="row g-4"><div class="col-lg-8"><div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Customer</th><th>Service</th><th>Frequency</th><th>Next Date</th><th>Technician</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['display_name'])?><small class="d-block text-muted"><?=e($r['property_label'])?></small></td><td><?=e($r['name'])?></td><td><?=e($r['frequency'])?></td><td><?=e($r['next_service_date'])?></td><td><?=e($r['technician']?:'Unassigned')?></td></tr><?php endforeach?></tbody></table></div></div></div><div class="col-lg-4"><div class="card card-body"><h2 class="h5">New Recurring Service</h2><form method="post" action="/portal/recurring"><?=csrf_field()?><select class="form-select mb-2" name="customer_id" required><option value="">Customer</option><?php foreach($customers as $c):?><option value="<?=$c['id']?>"><?=e($c['display_name'])?></option><?php endforeach?></select><select class="form-select mb-2" name="service_id"><option value="">Service</option><?php foreach($services as $s):?><option value="<?=$s['id']?>"><?=e($s['name'])?></option><?php endforeach?></select><input class="form-control mb-2" name="name" placeholder="Schedule name" required><select class="form-select mb-2" name="frequency"><?php foreach(['weekly','biweekly','monthly','quarterly','semiannual','annual','custom'] as $f):?><option><?=$f?></option><?php endforeach?></select><input class="form-control mb-2" type="number" name="interval_days" placeholder="Custom interval days"><input class="form-control mb-2" type="date" name="next_service_date" required><input class="form-control mb-2" type="time" name="preferred_start_time"><select class="form-select mb-2" name="assigned_user_id"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select><textarea class="form-control mb-3" name="notes" placeholder="Notes"></textarea><button class="btn btn-primary w-100">Create Schedule</button></form></div></div></div>
